// /frontend/src/components/Radar.jsx
import React, { useEffect, useRef, useState } from "react";
import L from "leaflet";
import "leaflet/dist/leaflet.css";

const OWM_KEY = process.env.REACT_APP_OWM_KEY || import.meta?.env?.VITE_OWM_KEY || "";
const CENTER = [33.749, -84.388];

const BASES = {
  osm: {
    label: "OSM",
    url: "https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png",
    opts: { maxZoom: 19, zIndex: 100, crossOrigin: true, updateWhenZooming: true, keepBuffer: 4 },
  },
  cartoDark: {
    label: "Dark",
    url: "https://{s}.tile.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png",
    opts: { subdomains: "abcd", maxZoom: 19, zIndex: 100, crossOrigin: true, updateWhenZooming: true, keepBuffer: 4 },
  },
  esriGray: {
    label: "Gray",
    url: "https://server.arcgisonline.com/ArcGIS/rest/services/Canvas/World_Light_Gray_Base/MapServer/tile/{z}/{y}/{x}",
    opts: { maxZoom: 16, zIndex: 100, crossOrigin: true, updateWhenZooming: true, keepBuffer: 4 },
  },
};

const OVERLAYS = {
  auto: { label: "Auto (fastest)" },
  mesonet: {
    label: "Mesonet",
    url: "https://mesonet.agron.iastate.edu/cache/tile.py/1.0.0/nexrad-n0q-900913/{z}/{x}/{y}.png",
    opts: { opacity: 0.85, zIndex: 500, crossOrigin: true, updateWhenZooming: true, keepBuffer: 4, noWrap: true },
    minZoom: 3,
    maxZoom: 12,
  },
  rainviewer: {
    label: "RainViewer",
    dynamic: true,
    opts: { opacity: 0.85, zIndex: 500, crossOrigin: true, updateWhenZooming: true, keepBuffer: 4 },
    minZoom: 0,
    maxZoom: 18,
  },
  owm: {
    label: "OWM",
    url: OWM_KEY ? `https://tile.openweathermap.org/map/precipitation_new/{z}/{x}/{y}.png?appid=${OWM_KEY}` : "",
    opts: { opacity: 0.85, zIndex: 500, crossOrigin: true, updateWhenZooming: true, keepBuffer: 4 },
    minZoom: 0,
    maxZoom: 18,
  },
};

export default function Radar() {
  const mapRef = useRef(null);
  const baseRef = useRef(null);
  const overlayRef = useRef(null);      // currently visible overlay
  const pendingRef = useRef(null);      // overlay being prepared

  const [provider, setProvider] = useState("auto"); // auto | mesonet | rainviewer | owm
  const [base, setBase] = useState("osm");
  const [activeOverlay, setActiveOverlay] = useState("");
  const [loading, setLoading] = useState(true);
  const [errorText, setErrorText] = useState("");

  useEffect(() => {
    if (mapRef.current) return;
    const map = L.map("radar-map", {
      zoomControl: false,
      attributionControl: false,
      preferCanvas: true,
      center: CENTER,
      zoom: 6,
    });
    mapRef.current = map;
    setTimeout(() => map.invalidateSize(), 0);

    map.on("zoomend", () => {
      const ov = OVERLAYS[activeOverlay] || OVERLAYS.mesonet;
      if (!ov) return;
      const z = map.getZoom();
      if (ov.maxZoom != null && z > ov.maxZoom) map.setZoom(ov.maxZoom);
      if (ov.minZoom != null && z < ov.minZoom) map.setZoom(ov.minZoom);
      overlayRef.current?.redraw?.();
    });
  }, [activeOverlay]);

  // Base layer
  useEffect(() => {
    const map = mapRef.current; if (!map) return;
    const cfg = BASES[base] || BASES.osm;
    baseRef.current && map.removeLayer(baseRef.current);
    baseRef.current = L.tileLayer(cfg.url, cfg.opts).addTo(map);
  }, [base]);

  // Helpers
  const clampZoomForOverlay = (id) => {
    const map = mapRef.current; if (!map) return;
    const meta = OVERLAYS[id];
    if (!meta) return;
    let z = map.getZoom();
    if (meta.maxZoom != null && z > meta.maxZoom) z = meta.maxZoom;
    if (meta.minZoom != null && z < meta.minZoom) z = meta.minZoom;
    if (z !== map.getZoom()) map.setZoom(z);
  };

  const createRainviewer = async () => {
    const meta = await fetch("https://api.rainviewer.com/public/weather-maps.json").then(r => r.json());
    const host = meta?.host || "";
    const frames = [...(meta?.radar?.past || []), ...(meta?.radar?.nowcast || [])];
    const last = frames.at(-1)?.time;
    if (!host || !last) throw new Error("No RainViewer frames");
    return L.tileLayer(`${host}/v2/radar/${last}/256/{z}/{x}/{y}.png`, OVERLAYS.rainviewer.opts);
  };

  // Double‑buffered overlay swap: keep old visible until new finishes loading
  const mountOverlay = (layer, id) => {
    const map = mapRef.current; if (!map) return;
    pendingRef.current = layer;

    // Add the new layer UNDER the old one briefly to avoid a flash
    layer.setZIndex(OVERLAYS[id]?.opts?.zIndex ?? 500);
    layer
      .on("load", () => {
        // new layer ready → remove old, promote new
        overlayRef.current && map.removeLayer(overlayRef.current);
        overlayRef.current = pendingRef.current;
        pendingRef.current = null;
        setActiveOverlay(id);
        clampZoomForOverlay(id);
        setLoading(false);
        setErrorText("");
      })
      .on("tileerror", () => {
        // leave old layer in place; show error
        pendingRef.current && map.removeLayer(pendingRef.current);
        pendingRef.current = null;
        setLoading(false);
        setErrorText(`${OVERLAYS[id]?.label || "Overlay"} tiles failed to load.`);
      })
      .addTo(map);
  };

  const setOverlay = async (id) => {
    const map = mapRef.current; if (!map) return;
    setLoading(true);
    setErrorText("");

    // Auto mode: race + keep current visible until a winner finishes loading
    if (id === "auto") {
      const contestants = [];

      const win = (layer, pid) => {
        // If something already won, ignore
        if (pendingRef.current === null && overlayRef.current) return;
        // Remove other pending contestants
        contestants.forEach(c => { if (c.layer && c.id !== pid) try { map.removeLayer(c.layer); } catch {} });
        mountOverlay(layer, pid);
      };

      // Mesonet
      const meso = L.tileLayer(OVERLAYS.mesonet.url, OVERLAYS.mesonet.opts)
        .on("load", () => win(meso, "mesonet"))
        .on("tileerror", () => {});
      meso.addTo(map); contestants.push({ id: "mesonet", layer: meso });

      // RainViewer
      createRainviewer().then(rv => {
        rv.on("load", () => win(rv, "rainviewer")).on("tileerror", () => {});
        rv.addTo(map); contestants.push({ id: "rainviewer", layer: rv });
      }).catch(() => {});

      // OWM
      if (OVERLAYS.owm.url) {
        const owm = L.tileLayer(OVERLAYS.owm.url, OVERLAYS.owm.opts)
          .on("load", () => win(owm, "owm"))
          .on("tileerror", () => {});
        owm.addTo(map); contestants.push({ id: "owm", layer: owm });
      }

      // safety timeout
      setTimeout(() => {
        if (!overlayRef.current && !pendingRef.current) {
          setLoading(false);
          setErrorText("Radar tiles didn’t load. Try another provider.");
        }
      }, 6000);

      return;
    }

    // Manual: prepare new layer but DO NOT remove old until new is ready
    try {
      let layer;
      if (id === "mesonet") {
        layer = L.tileLayer(OVERLAYS.mesonet.url, OVERLAYS.mesonet.opts);
      } else if (id === "rainviewer") {
        layer = await createRainviewer();
      } else if (id === "owm") {
        if (!OVERLAYS.owm.url) throw new Error("Set REACT_APP_OWM_KEY / VITE_OWM_KEY");
        layer = L.tileLayer(OVERLAYS.owm.url, OVERLAYS.owm.opts);
      } else {
        return;
      }
      mountOverlay(layer, id);
    } catch (e) {
      setErrorText(e?.message || "Radar failed.");
      setLoading(false);
    }
  };

  useEffect(() => { setOverlay(provider); /* eslint-disable-next-line */ }, [provider]);

  return (
    <div className="relative rounded-2xl overflow-hidden backdrop-blur-xl bg-black/40 ring-1 ring-white/10">
      {/* Compact controls — force readable colors to avoid white-on-white native menu */}
      <div className="flex items-center justify-between px-3 py-2 gap-2">
        <div className="text-sm opacity-80 truncate">
          Radar {activeOverlay ? `• ${OVERLAYS[activeOverlay]?.label || activeOverlay}` : ""}
        </div>
        <div className="flex gap-2">
          <select
            value={provider}
            onChange={(e) => setProvider(e.target.value)}
            aria-label="Provider"
            className="text-xs px-2 py-1 rounded outline-none"
            // Force contrasting native menu colors across platforms
            style={{ backgroundColor: "#ffffff", color: "#000000" }}
          >
            {Object.entries(OVERLAYS).map(([k, v]) => (
              <option key={k} value={k} disabled={k === "owm" && !OWM_KEY}>
                {v.label}{k === "owm" && !OWM_KEY ? " (set key)" : ""}
              </option>
            ))}
          </select>

          <select
            value={base}
            onChange={(e) => setBase(e.target.value)}
            aria-label="Base map"
            className="text-xs px-2 py-1 rounded outline-none"
            style={{ backgroundColor: "#ffffff", color: "#000000" }}
          >
            {Object.entries(BASES).map(([k, v]) => (
              <option key={k} value={k}>{v.label}</option>
            ))}
          </select>
        </div>
      </div>

      <div id="radar-map" style={{ height: 320, width: "100%" }} />

      {loading && (
        <div className="absolute inset-0 grid place-items-center pointer-events-none">
          <div className="animate-spin h-6 w-6 rounded-full border-2 border-white/30 border-t-white" />
        </div>
      )}

      {!!errorText && !loading && (
        <div className="absolute bottom-2 left-2 right-2 text-xs px-2 py-1 rounded bg-black/70 ring-1 ring-white/10">
          {errorText}
        </div>
      )}
    </div>
  );
}
